const body = $input.first().json.body || $input.first().json;

return [{
  json: {
    candidateName: body.name || '',
    email: body.email || '',
    phone: body.phone || '',
    position: body.position || body.role || '',
    cvText: body.cv_text || body.resume_text || '',
    cvUrl: body.cv_url || '',
    source: body.source || 'direct',
    appliedAt: new Date().toISOString()
  }
}];

const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '{}';

let parsed;
try {
  const match = content.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : content);
} catch {
  parsed = {
    name: $('Parse Application').first().json.candidateName,
    email: $('Parse Application').first().json.email,
    phone: $('Parse Application').first().json.phone,
    location: '',
    years_experience: 0,
    current_title: '',
    skills: [],
    education: [],
    languages: [],
    visa_status: '',
    summary: 'CV parsing failed — manual review required'
  };
}

return [{
  json: {
    parsedCV: parsed,
    position: $('Parse Application').first().json.position,
    candidateName: parsed.name || $('Parse Application').first().json.candidateName,
    email: parsed.email || $('Parse Application').first().json.email
  }
}];

const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '{}';

let scoring;
try {
  const match = content.match(/\{[\s\S]*\}/);
  scoring = JSON.parse(match ? match[0] : content);
} catch {
  scoring = { score: 50, tier: 'hold', recommendation: 'Manual review needed — scoring parse failed', strengths: [], gaps: [], interview_questions: [] };
}

const application = $('Parse Application').first().json;
const parsedCV = $('Extract Parsed CV').first().json.parsedCV;

return [{
  json: {
    candidateName: application.candidateName || parsedCV.name || '',
    email: application.email || parsedCV.email || '',
    phone: application.phone || parsedCV.phone || '',
    position: application.position,
    source: application.source,
    appliedAt: application.appliedAt,
    score: scoring.score || 50,
    tier: scoring.tier || 'hold',
    breakdown: scoring.breakdown || {},
    strengths: scoring.strengths || [],
    gaps: scoring.gaps || [],
    recommendation: scoring.recommendation || '',
    interviewQuestions: scoring.interview_questions || [],
    parsedCV: parsedCV
  }
}];

const response = $input.first().json;
const emailContent = response.choices?.[0]?.message?.content || 'Interview invitation — email generation pending';
const candidate = $('Parse Scoring').first().json;

return [{
  json: {
    ...candidate,
    emailGenerated: emailContent,
    emailType: 'interview_invitation'
  }
}];

// Hold candidates: log for manual review, no email generated
const candidate = $json;

return [{
  json: {
    ...candidate,
    emailGenerated: null,
    emailType: 'hold_for_review',
    action: 'Flagged for manual hiring manager review'
  }
}];

const response = $input.first().json;
const emailContent = response.choices?.[0]?.message?.content || 'Rejection email — generation pending';
const candidate = $('Parse Scoring').first().json;

return [{
  json: {
    ...candidate,
    emailGenerated: emailContent,
    emailType: 'rejection'
  }
}];
